document.addEventListener('DOMContentLoaded',()=>{document.querySelectorAll('[data-nav-toggle]').forEach(btn=>btn.addEventListener('click',()=>{document.querySelector('[data-nav]')?.classList.toggle('is-open')}));document.querySelectorAll('[data-accordion]').forEach(acc=>{acc.querySelectorAll('.accordion-trigger').forEach(btn=>btn.addEventListener('click',()=>btn.parentElement.classList.toggle('is-open')))});});